INSERT INTO bug_reports VALUES(1,'feature','dodati br stola na kome se igra','stol na kome se igra bi trebao biti kao parametar na meču jer ga treba birati na osnovu slobodnog mjesta. neki mečevi se brže završe pa je na turniru bitno da se primjeti da je stol slobodan i da ga se dodjeli sljedećem meču koji se igra. (Mada to i sudija prijavi kad završi meč). Obično na početku sudija bude vezan uz stol dok su svi stolovi popunjeni, al mislim da se sudije kasnije biraju po iskustvu ako je meč ozbiljniji',NULL,NULL,4,'resolved',NULL,'2025-10-23 10:26:09','2025-10-22 13:48:22','2025-10-23 10:26:09');
