PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE IF NOT EXISTS "migrations" ("id" integer primary key autoincrement not null, "migration" varchar not null, "batch" integer not null);
CREATE TABLE IF NOT EXISTS "users" ("id" integer primary key autoincrement not null, "name" varchar not null, "email" varchar not null, "email_verified_at" datetime, "password" varchar not null, "remember_token" varchar, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "password_reset_tokens" ("email" varchar not null, "token" varchar not null, "created_at" datetime, primary key ("email"));
CREATE TABLE IF NOT EXISTS "sessions" ("id" varchar not null, "user_id" integer, "ip_address" varchar, "user_agent" text, "payload" text not null, "last_activity" integer not null, primary key ("id"));
CREATE TABLE IF NOT EXISTS "cache" ("key" varchar not null, "value" text not null, "expiration" integer not null, primary key ("key"));
CREATE TABLE IF NOT EXISTS "cache_locks" ("key" varchar not null, "owner" varchar not null, "expiration" integer not null, primary key ("key"));
CREATE TABLE IF NOT EXISTS "jobs" ("id" integer primary key autoincrement not null, "queue" varchar not null, "payload" text not null, "attempts" integer not null, "reserved_at" integer, "available_at" integer not null, "created_at" integer not null);
CREATE TABLE IF NOT EXISTS "job_batches" ("id" varchar not null, "name" varchar not null, "total_jobs" integer not null, "pending_jobs" integer not null, "failed_jobs" integer not null, "failed_job_ids" text not null, "options" text, "cancelled_at" integer, "created_at" integer not null, "finished_at" integer, primary key ("id"));
CREATE TABLE IF NOT EXISTS "failed_jobs" ("id" integer primary key autoincrement not null, "uuid" varchar not null, "connection" text not null, "queue" text not null, "payload" text not null, "exception" text not null, "failed_at" datetime not null default CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS "sports" ("id" integer primary key autoincrement not null, "name" varchar not null, "slug" varchar not null, "description" text, "icon" varchar, "is_active" tinyint(1) not null default '1', "created_at" datetime, "updated_at" datetime, "rules" text, "active" tinyint(1) not null default '1');
CREATE TABLE IF NOT EXISTS "plans" ("id" integer primary key autoincrement not null, "name" varchar not null, "slug" varchar not null, "description" text, "price" numeric not null default '0', "currency" varchar not null default 'EUR', "max_organizations" integer not null default '1', "max_leagues_per_organization" integer not null default '2', "max_teams_per_league" integer not null default '10', "max_players_per_team" integer not null default '20', "is_active" tinyint(1) not null default '1', "features" text, "created_at" datetime, "updated_at" datetime, "max_competitions_per_organization" integer not null default '10');
CREATE TABLE IF NOT EXISTS "user_plans" ("id" integer primary key autoincrement not null, "user_id" integer not null, "plan_id" integer not null, "started_at" datetime, "expires_at" datetime, "is_active" tinyint(1) not null default '1', "created_at" datetime, "updated_at" datetime, foreign key("user_id") references "users"("id") on delete cascade, foreign key("plan_id") references "plans"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "organizations" ("id" integer primary key autoincrement not null, "name" varchar not null, "slug" varchar not null, "description" text, "logo" varchar, "user_id" integer not null, "is_active" tinyint(1) not null default ('1'), "created_at" datetime, "updated_at" datetime, foreign key("user_id") references users("id") on delete cascade on update no action);
CREATE TABLE IF NOT EXISTS "players" ("id" integer primary key autoincrement not null, "name" varchar not null, "email" varchar, "user_id" integer, "organization_id" integer not null, "date_of_birth" date, "position" varchar, "jersey_number" integer, "is_active" tinyint(1) not null default '1', "created_at" datetime, "updated_at" datetime, foreign key("user_id") references "users"("id") on delete set null, foreign key("organization_id") references "organizations"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "team_user" ("id" integer primary key autoincrement not null, "team_id" integer not null, "user_id" integer not null, "joined_at" datetime not null default CURRENT_TIMESTAMP, "created_at" datetime, "updated_at" datetime, foreign key("team_id") references "teams"("id") on delete cascade, foreign key("user_id") references "users"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "friendly_matches" ("id" integer primary key autoincrement not null, "organization_id" integer not null, "home_player_id" integer not null, "away_player_id" integer not null, "home_player_name" varchar not null, "away_player_name" varchar not null, "sets" text not null, "set_durations" text not null, "winner_name" varchar not null, "completed_at" datetime not null, "created_at" datetime, "updated_at" datetime, foreign key("organization_id") references "organizations"("id") on delete cascade, foreign key("home_player_id") references "players"("id") on delete cascade, foreign key("away_player_id") references "players"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "bug_reports" ("id" integer primary key autoincrement not null, "type" varchar check ("type" in ('bug', 'feature')) not null, "subject" varchar not null, "description" text not null, "name" varchar, "email" varchar, "user_id" integer, "status" varchar check ("status" in ('pending', 'in_review', 'resolved', 'closed')) not null default 'pending', "admin_notes" text, "resolved_at" datetime, "created_at" datetime, "updated_at" datetime, foreign key("user_id") references "users"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "organization_user" ("id" integer primary key autoincrement not null, "organization_id" integer not null, "user_id" integer not null, "role" varchar check ("role" in ('owner', 'referee')) not null default 'referee', "joined_at" datetime not null default CURRENT_TIMESTAMP, "created_at" datetime, "updated_at" datetime, foreign key("organization_id") references "organizations"("id") on delete cascade, foreign key("user_id") references "users"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "teams" ("id" integer primary key autoincrement not null, "name" varchar not null, "description" text, "competition_id" integer not null, "captain_id" integer, "status" varchar not null default ('active'), "created_at" datetime, "updated_at" datetime, foreign key("captain_id") references users("id") on delete set null on update no action, foreign key("competition_id") references "competitions"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "competition_user" ("id" integer primary key autoincrement not null, "competition_id" integer not null, "user_id" integer not null, "joined_at" datetime not null default (CURRENT_TIMESTAMP), "created_at" datetime, "updated_at" datetime, foreign key("user_id") references users("id") on delete cascade on update no action, foreign key("competition_id") references "competitions"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "competition_player" ("id" integer primary key autoincrement not null, "competition_id" integer not null, "player_id" integer not null, "joined_at" datetime not null default (CURRENT_TIMESTAMP), "created_at" datetime, "updated_at" datetime, "team_id" integer, foreign key("team_id") references teams("id") on delete set null on update no action, foreign key("player_id") references players("id") on delete cascade on update no action, foreign key("competition_id") references "competitions"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "notifications" ("id" varchar not null, "type" varchar not null, "notifiable_type" varchar not null, "notifiable_id" integer not null, "data" text not null, "read_at" datetime, "created_at" datetime, "updated_at" datetime, primary key ("id"));
CREATE TABLE IF NOT EXISTS "tournament_groups" ("id" integer primary key autoincrement not null, "competition_id" integer not null, "name" varchar not null, "group_number" integer not null, "player_ids" text, "standings" text, "is_completed" tinyint(1) not null default '0', "completed_at" datetime, "created_at" datetime, "updated_at" datetime, foreign key("competition_id") references "competitions"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "standings" ("id" integer primary key autoincrement not null, "created_at" datetime, "updated_at" datetime, "competition_id" integer not null, "team_id" integer, "player_id" integer, "position" integer not null default ('1'), "played" integer not null default ('0'), "won" integer not null default ('0'), "drawn" integer not null default ('0'), "lost" integer not null default ('0'), "goals_for" integer not null default ('0'), "goals_against" integer not null default ('0'), "goal_difference" integer not null default ('0'), "points" integer not null default ('0'), "sets_won" integer not null default '0', "sets_lost" integer not null default '0', "points_won" integer not null default '0', "points_lost" integer not null default '0', "tournament_group_id" integer, foreign key("competition_id") references competitions("id") on delete cascade on update no action, foreign key("team_id") references teams("id") on delete cascade on update no action, foreign key("player_id") references players("id") on delete cascade on update no action, foreign key("tournament_group_id") references "tournament_groups"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "competitions" ("id" integer primary key autoincrement not null, "name" varchar not null, "slug" varchar not null, "description" text, "organization_id" integer not null, "sport_id" integer not null, "type" varchar not null default ('league'), "start_date" date, "end_date" date, "max_teams" integer not null default ('8'), "is_team_based" tinyint(1) not null default ('0'), "status" varchar not null default ('draft'), "settings" text, "is_active" tinyint(1) not null default ('1'), "max_participants" integer not null default ('16'), "group_count" integer not null default ('4'), "players_per_group" integer not null default ('4'), "players_advancing_per_group" integer not null default ('2'), "advancement_method" varchar not null default ('automatic'), "current_phase" varchar not null default ('groups'), "knockout_bracket" text, "groups_completed_at" datetime, "knockout_completed_at" datetime, "sets_to_win" integer not null default ('2'), "points_per_set" integer not null default ('21'), "deuce_at" integer not null default ('20'), "must_win_by_two" tinyint(1) not null default ('1'), "points_for_win" integer not null default ('3'), "points_for_draw" integer not null default ('1'), "points_for_loss" integer not null default ('0'), "has_tiebreak" tinyint(1) not null default ('1'), "tiebreak_points" integer not null default ('7'), "created_at" datetime, "updated_at" datetime, "manual_knockout_selection" tinyint(1) not null default '0', "is_public" tinyint(1) not null default '0', foreign key("sport_id") references sports("id") on delete cascade on update no action, foreign key("organization_id") references organizations("id") on delete cascade on update no action);
CREATE TABLE IF NOT EXISTS "display_leagues" ("id" integer primary key autoincrement not null, "league_id" integer not null, "display_order" integer not null default '0', "created_at" datetime, "updated_at" datetime, foreign key("league_id") references "leagues"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "tables" ("id" integer primary key autoincrement not null, "organization_id" integer not null, "name" varchar not null, "description" text, "is_active" tinyint(1) not null default '1', "created_at" datetime, "updated_at" datetime, foreign key("organization_id") references "organizations"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "matches" ("id" integer primary key autoincrement not null, "created_at" datetime, "updated_at" datetime, "league_id" integer, "home_team_id" integer, "away_team_id" integer, "home_player_id" integer, "away_player_id" integer, "home_score" integer, "away_score" integer, "scheduled_at" datetime, "played_at" datetime, "status" varchar not null default ('scheduled'), "forfeited_by" varchar, "round" integer not null default ('1'), "sets" text, "first_server" varchar, "current_server" varchar, "set_durations" text, "current_set_started_at" datetime, "competition_id" integer, "phase" varchar, "tournament_group_id" integer, "round_number" integer, "bracket_position" integer, "is_bye" tinyint(1) not null default ('0'), "moderator_id" integer, "edited_by" integer, "completed_by" integer, "edited_at" datetime, "completed_at" datetime, "table_id" integer, "referee_user_id" integer, "match_order" integer, foreign key("tournament_group_id") references tournament_groups("id") on delete cascade on update no action, foreign key("away_player_id") references players("id") on delete cascade on update no action, foreign key("home_player_id") references players("id") on delete cascade on update no action, foreign key("away_team_id") references teams("id") on delete cascade on update no action, foreign key("home_team_id") references teams("id") on delete cascade on update no action, foreign key("league_id") references competitions("id") on delete cascade on update no action, foreign key("competition_id") references competitions("id") on delete cascade on update no action, foreign key("moderator_id") references users("id") on delete set null on update no action, foreign key("edited_by") references users("id") on delete set null on update no action, foreign key("completed_by") references users("id") on delete set null on update no action);
DELETE FROM sqlite_sequence;
CREATE UNIQUE INDEX "users_email_unique" on "users" ("email");
CREATE INDEX "sessions_user_id_index" on "sessions" ("user_id");
CREATE INDEX "sessions_last_activity_index" on "sessions" ("last_activity");
CREATE INDEX "jobs_queue_index" on "jobs" ("queue");
CREATE UNIQUE INDEX "failed_jobs_uuid_unique" on "failed_jobs" ("uuid");
CREATE UNIQUE INDEX "sports_slug_unique" on "sports" ("slug");
CREATE UNIQUE INDEX "plans_slug_unique" on "plans" ("slug");
CREATE UNIQUE INDEX "unique_active_user_plan" on "user_plans" ("user_id", "is_active");
CREATE UNIQUE INDEX "organizations_slug_unique" on "organizations" ("slug");
CREATE INDEX "players_organization_id_is_active_index" on "players" ("organization_id", "is_active");
CREATE INDEX "players_user_id_organization_id_index" on "players" ("user_id", "organization_id");
CREATE UNIQUE INDEX "team_user_team_id_user_id_unique" on "team_user" ("team_id", "user_id");
CREATE UNIQUE INDEX "organization_user_organization_id_user_id_unique" on "organization_user" ("organization_id", "user_id");
CREATE UNIQUE INDEX "league_user_league_id_user_id_unique" on "competition_user" ("competition_id", "user_id");
CREATE UNIQUE INDEX "league_player_league_id_player_id_unique" on "competition_player" ("competition_id", "player_id");
CREATE INDEX "notifications_notifiable_type_notifiable_id_index" on "notifications" ("notifiable_type", "notifiable_id");
CREATE INDEX "standings_competition_played_critical" on "standings" ("competition_id", "played");
CREATE INDEX "standings_competition_points_critical" on "standings" ("competition_id", "points");
CREATE UNIQUE INDEX "competitions_slug_unique" on "competitions" ("slug");
CREATE INDEX "idx_standings_league_id" on "standings" ("league_id");
CREATE INDEX "idx_standings_competition_id" on "standings" ("competition_id");
CREATE INDEX "idx_standings_team_id" on "standings" ("team_id");
CREATE INDEX "idx_standings_player_id" on "standings" ("player_id");
CREATE INDEX "idx_standings_tournament_group_id" on "standings" ("tournament_group_id");
CREATE INDEX "idx_standings_position" on "standings" ("position");
CREATE INDEX "idx_standings_league_position" on "standings" ("league_id", "position");
CREATE INDEX "idx_standings_competition_position" on "standings" ("competition_id", "position");
CREATE INDEX "idx_standings_group_position" on "standings" ("tournament_group_id", "position");
CREATE INDEX "idx_standings_league_points_gd" on "standings" ("league_id", "points", "goal_difference");
CREATE INDEX "idx_standings_competition_points_sets" on "standings" ("competition_id", "points", "sets_won");
CREATE INDEX "idx_players_user_id" on "players" ("user_id");
CREATE INDEX "idx_players_organization_id" on "players" ("organization_id");
CREATE INDEX "idx_players_is_active" on "players" ("is_active");
CREATE INDEX "idx_players_org_active" on "players" ("organization_id", "is_active");
CREATE INDEX "idx_players_user_org" on "players" ("user_id", "organization_id");
CREATE INDEX "idx_teams_competition_id" on "teams" ("competition_id");
CREATE INDEX "idx_teams_competition_type" on "teams" ("competition_type");
CREATE INDEX "idx_teams_competition_lookup" on "teams" ("competition_type", "competition_id");
CREATE INDEX "players_user_id_index" on "players" ("user_id");
CREATE INDEX "players_organization_id_index" on "players" ("organization_id");
CREATE INDEX "players_is_active_index" on "players" ("is_active");
CREATE INDEX "idx_matches_competition_id" on "matches" ("competition_id");
CREATE INDEX "idx_matches_competition_status_scheduled" on "matches" ("competition_id", "status", "scheduled_at");
CREATE INDEX "idx_matches_league_id" on "matches" ("league_id");
CREATE INDEX "idx_matches_league_status_scheduled" on "matches" ("league_id", "status", "scheduled_at");
CREATE INDEX "idx_matches_moderator_id" on "matches" ("moderator_id");
CREATE INDEX "idx_matches_played_at" on "matches" ("played_at");
CREATE INDEX "idx_matches_referee_user_id" on "matches" ("referee_user_id");
CREATE INDEX "idx_matches_round" on "matches" ("round");
CREATE INDEX "idx_matches_scheduled_at" on "matches" ("scheduled_at");
CREATE INDEX "idx_matches_status" on "matches" ("status");
CREATE INDEX "idx_matches_status_moderator" on "matches" ("status", "moderator_id");
CREATE INDEX "idx_matches_status_referee" on "matches" ("status", "referee_user_id");
CREATE INDEX "idx_matches_tournament_group_id" on "matches" ("tournament_group_id");
CREATE INDEX "matches_competition_status_critical" on "matches" ("competition_id", "status");
CREATE INDEX "matches_dates_critical" on "matches" ("scheduled_at", "played_at");
CREATE INDEX "matches_status_scheduled_critical" on "matches" ("status", "scheduled_at");
CREATE INDEX "matches_status_updated_live_scoring" on "matches" ("status", "updated_at");
CREATE INDEX "matches_updated_at_live_scoring" on "matches" ("updated_at");
CREATE INDEX "matches_competition_status_updated_live" on "matches" ("competition_id", "status", "updated_at");
COMMIT;
